import React, { useState, useEffect } from "react";
import {
  ResponsiveContainer, LineChart, Line, XAxis, YAxis, CartesianGrid,
  Tooltip, BarChart, Bar, Cell, LabelList,
} from "recharts";

/* ================================================================== *
 *  Panel FIV — shell con menú lateral + dashboards
 *  - Sidebar colapsable que lista los dashboards (activos / pendientes / próximos)
 *  - Dashboard 1 (Tasa de blastos): funcional, datos de muestra
 *  - Dashboard 2 (Tasa de embarazo): panel de estado (bloqueado por el join)
 *  El backend de FastAPI sustituye los datos de muestra por el API.
 * ================================================================== */

// Paleta corporativa Ingenes (azul marino de la "g", verde del espermatozoide, gris del texto)
const C = {
  bg: "#F4F6FA", surface: "#FFFFFF", ink: "#1B2A4A", inkSoft: "#41506B",
  muted: "#7C879B", line: "#E4E8F0", lineSoft: "#EEF1F7", primary: "#1E3A6E",
  primarySoft: "#8FB94A", green: "#8CC63F", clay: "#C79A3E", up: "#5FA030", down: "#C0504A",
  sidebar: "#16305C", sidebarInk: "#C7D2E6", sidebarMut: "#7E8FB2",
};
const LOGO_INGENES = "data:image/png;base64,";
const LOGO_ANIOS   = "data:image/jpeg;base64,";
const FONT_DISPLAY = '"Georgia","Times New Roman",serif';
const FONT_MONO = 'ui-monospace,"SF Mono","Roboto Mono",Menlo,monospace';
const FONT_UI = '"Inter",system-ui,-apple-system,sans-serif';

// ---------- DASHBOARD BLASTOS (contenido) ----------
function aniosARango(anios) {
  const toISO = (d) => d.toISOString().slice(0, 10);
  const hoy = new Date();
  if (!anios.length) return { desde: "2000-01-01", hasta: toISO(hoy) };
  const nums = anios.map((a) => parseInt(a, 10));
  const min = Math.min(...nums), max = Math.max(...nums);
  const hasta = max === hoy.getFullYear() ? toISO(hoy) : `${max}-12-31`;
  return { desde: `${min}-01-01`, hasta };
}

function DashboardBlastosBody() {
  const [anios, setAnios] = useState(ANIOS);
  const [pais, setPais] = useState("all");
  const [numKey, setNumKey] = useState("blastos_all");
  const [denKey, setDenKey] = useState("ov_cap");
  const [rankBy, setRankBy] = useState("medico");

  const [catalogoMedicos, setCatalogoMedicos] = useState([]);
  const [catalogoSucursales, setCatalogoSucursales] = useState([]);
  const [catalogoTiposCiclo, setCatalogoTiposCiclo] = useState([]);
  const [catalogoTecnicas, setCatalogoTecnicas] = useState([]);
  const [medicos, setMedicos] = useState([]);
  const [sucursales, setSucursales] = useState([]);
  const [tiposCiclo, setTiposCiclo] = useState([]);
  const [tecnicas, setTecnicas] = useState([]);
  const [catalogosListos, setCatalogosListos] = useState(false);

  const [data, setData] = useState(null);
  const [error, setError] = useState(null);

  // Catálogos (médicos/sucursales/tipo de ciclo/técnica reales) — se cargan una sola vez.
  useEffect(() => {
    fetch("/api/catalogos").then((r) => r.json()).then((json) => {
      setCatalogoMedicos(json.medicos);
      setCatalogoSucursales(json.sucursales.map((s) => [s.nombre, s.pais]));
      setCatalogoTiposCiclo(json.tiposCiclo);
      setCatalogoTecnicas(json.tecnicas);
      setMedicos(json.medicos);
      setSucursales(json.sucursales.map((s) => s.nombre));
      setTiposCiclo(json.tiposCiclo);
      setTecnicas(json.tecnicas);
      setCatalogosListos(true);
    }).catch((e) => setError(String(e)));
  }, []);

  // Datos del dashboard — se recargan cuando cambia cualquier filtro.
  useEffect(() => {
    if (!catalogosListos) return;
    const { desde, hasta } = aniosARango(anios);
    const params = new URLSearchParams({ desde, hasta, numerador: numKey, denominador: denKey, pais });
    if (anios.length < ANIOS.length) anios.forEach((a) => params.append("anio", a));
    if (medicos.length < catalogoMedicos.length) medicos.forEach((m) => params.append("medico", m));
    if (sucursales.length < catalogoSucursales.length) sucursales.forEach((s) => params.append("sucursal", s));
    if (tiposCiclo.length < catalogoTiposCiclo.length) tiposCiclo.forEach((t) => params.append("origen", t));
    if (tecnicas.length < catalogoTecnicas.length) tecnicas.forEach((t) => params.append("tecnica", t));
    let cancelado = false;
    fetch(`/api/dashboards/blastos?${params}`).then((r) => r.json()).then((json) => {
      if (!cancelado) { setData(json); setError(null); }
    }).catch((e) => { if (!cancelado) setError(String(e)); });
    return () => { cancelado = true; };
  }, [catalogosListos, anios, pais, numKey, denKey, medicos, sucursales, tiposCiclo, tecnicas, catalogoMedicos.length, catalogoSucursales.length, catalogoTiposCiclo.length, catalogoTecnicas.length]);

  const tog = (arr, set, v) => set(arr.includes(v) ? arr.filter((x) => x !== v) : [...arr, v]);
  const numLabel = NUMERADORES[numKey].label, denLabel = DENOMINADORES[denKey].label;

  if (error) return <div style={{ padding: 22, color: C.down }}>Error cargando el dashboard: {error}</div>;
  if (!data) return <div style={{ padding: 22, color: C.muted }}>Cargando…</div>;

  const serie = data.serie, ranking = data.ranking[rankBy], tabla = data.tabla;

  return (
    <div style={{ padding: "22px 24px" }}>
      <div style={{ marginBottom: 4 }}>
        <div style={{ fontFamily: FONT_DISPLAY, fontSize: 25, fontWeight: 600, letterSpacing: -.3 }}>Tasa de blastos sobre óvulos</div>
        <div style={{ fontSize: 13, color: C.muted, marginTop: 2 }}>{numLabel} ÷ {denLabel} · {fmtInt(data.kpis.ciclos)} ciclos en vista</div>
      </div>

      <div style={{ display: "flex", flexWrap: "wrap", gap: 10, alignItems: "center", background: C.surface, border: `1px solid ${C.line}`, borderRadius: 12, padding: 12, margin: "14px 0 16px" }}>
        <MultiSelect label="Año" options={ANIOS} selected={anios} onToggle={(v) => tog(anios, setAnios, v)} onAll={() => setAnios(anios.length === ANIOS.length ? [] : [...ANIOS])} />
        <div style={{ width: 1, height: 22, background: C.line }} />
        <Segmented options={[{ value: "all", label: "Ambos países" }, { value: "MX", label: "México" }, { value: "US", label: "EEUU" }]} value={pais} onChange={setPais} />
        <MultiSelect label="Médico" options={catalogoMedicos} selected={medicos} onToggle={(v) => tog(medicos, setMedicos, v)} onAll={() => setMedicos(medicos.length === catalogoMedicos.length ? [] : [...catalogoMedicos])} />
        <MultiSelect label="Sucursal" options={catalogoSucursales.map((s) => s[0])} selected={sucursales} onToggle={(v) => tog(sucursales, setSucursales, v)} onAll={() => setSucursales(sucursales.length === catalogoSucursales.length ? [] : catalogoSucursales.map((s) => s[0]))} />
        <MultiSelect label="Tipo de ciclo" options={catalogoTiposCiclo} selected={tiposCiclo} onToggle={(v) => tog(tiposCiclo, setTiposCiclo, v)} onAll={() => setTiposCiclo(tiposCiclo.length === catalogoTiposCiclo.length ? [] : [...catalogoTiposCiclo])} />
        <MultiSelect label="Técnica" options={catalogoTecnicas} selected={tecnicas} onToggle={(v) => tog(tecnicas, setTecnicas, v)} onAll={() => setTecnicas(tecnicas.length === catalogoTecnicas.length ? [] : [...catalogoTecnicas])} />
      </div>

      <div style={{ display: "flex", gap: 18, flexWrap: "wrap", marginBottom: 16 }}>
        <label style={{ fontSize: 12, color: C.muted, display: "flex", alignItems: "center", gap: 7 }}>Numerador
          <select value={numKey} onChange={(e) => setNumKey(e.target.value)} style={{ fontFamily: FONT_UI, fontSize: 12.5, padding: "5px 8px", borderRadius: 7, border: `1px solid ${C.line}`, color: C.ink, background: C.surface }}>{Object.entries(NUMERADORES).map(([k, v]) => <option key={k} value={k}>{v.label}</option>)}</select>
        </label>
        <label style={{ fontSize: 12, color: C.muted, display: "flex", alignItems: "center", gap: 7 }}>Denominador
          <select value={denKey} onChange={(e) => setDenKey(e.target.value)} style={{ fontFamily: FONT_UI, fontSize: 12.5, padding: "5px 8px", borderRadius: 7, border: `1px solid ${C.line}`, color: C.ink, background: C.surface }}>{Object.entries(DENOMINADORES).map(([k, v]) => <option key={k} value={k}>{v.label}</option>)}</select>
        </label>
      </div>

      <div style={{ display: "flex", gap: 12, flexWrap: "wrap", marginBottom: 16 }}>
        <Kpi label="Tasa de blastos" value={fmtPct(data.kpis.tasa)} sub={`n=${fmtInt(data.kpis.ovulos)} óvulos`} />
        <Kpi label={`Blastos (${numKey === "blastos_all" ? "todos" : "bonitos"})`} value={fmtInt(data.kpis.blastos)} sub="numerador" />
        <Kpi label="Óvulos" value={fmtInt(data.kpis.ovulos)} sub={denLabel.toLowerCase()} />
        <Kpi label="Ciclos" value={fmtInt(data.kpis.ciclos)} sub="punciones con captura" />
      </div>

      <div style={{ background: C.surface, border: `1px solid ${C.line}`, borderRadius: 12, padding: "16px 18px 8px", marginBottom: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
          <div style={{ fontSize: 14, fontWeight: 600, color: C.ink }}>Evolución de la tasa</div>
        </div>
        <ResponsiveContainer width="100%" height={230}>
          <LineChart data={serie} margin={{ top: 4, right: 8, left: -12, bottom: 0 }}>
            <CartesianGrid stroke={C.lineSoft} vertical={false} />
            <XAxis dataKey="mes" tickFormatter={mesLabel} tick={{ fontSize: 11, fill: C.muted }} tickLine={false} axisLine={{ stroke: C.line }} />
            <YAxis unit="%" tick={{ fontSize: 11, fill: C.muted }} tickLine={false} axisLine={false} width={44} />
            <Tooltip contentStyle={{ fontFamily: FONT_UI, fontSize: 12, borderRadius: 8, border: `1px solid ${C.line}` }} labelFormatter={mesLabel} formatter={(v, n) => [v == null ? "—" : `${v}%`, n]} />
            <Line type="monotone" dataKey="tasa" name="Tasa" stroke={C.primary} strokeWidth={2.2} dot={{ r: 2.5, fill: C.primary }} activeDot={{ r: 4 }} connectNulls />
          </LineChart>
        </ResponsiveContainer>
      </div>

      <div style={{ background: C.surface, border: `1px solid ${C.line}`, borderRadius: 12, padding: "16px 18px", marginBottom: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
          <div style={{ fontSize: 14, fontWeight: 600, color: C.ink }}>Comparativo por {rankBy === "medico" ? "médico" : "sucursal"}</div>
          <Segmented options={[{ value: "medico", label: "Médico" }, { value: "sucursal", label: "Sucursal" }]} value={rankBy} onChange={setRankBy} />
        </div>
        <div style={{ maxHeight: 380, overflowY: "auto" }}>
          <ResponsiveContainer width="100%" height={ranking.length * 30 + 20}>
            <BarChart data={ranking} layout="vertical" margin={{ top: 0, right: 54, left: 8, bottom: 0 }}>
              <CartesianGrid stroke={C.lineSoft} horizontal={false} />
              <XAxis type="number" unit="%" tick={{ fontSize: 11, fill: C.muted }} tickLine={false} axisLine={false} />
              <YAxis type="category" dataKey="clave" width={rankBy === "medico" ? 168 : 108} tickFormatter={(v) => truncar(v, rankBy === "medico" ? 24 : 16)} tick={{ fontSize: 12, fill: C.inkSoft }} tickLine={false} axisLine={false} interval={0} />
              <Tooltip cursor={{ fill: C.lineSoft }} contentStyle={{ fontFamily: FONT_UI, fontSize: 12, borderRadius: 8, border: `1px solid ${C.line}` }} labelFormatter={(v) => v} formatter={(v, n, p) => [`${v}%  ·  n=${fmtInt(p.payload.n)} · ${p.payload.ciclos} ciclos`, "Tasa"]} />
              <Bar dataKey="tasa" radius={[0, 4, 4, 0]} barSize={18}>
                {ranking.map((r, i) => <Cell key={i} fill={i === 0 ? C.primary : C.primarySoft} />)}
                <LabelList dataKey="tasa" position="right" formatter={(v) => `${v}%`} style={{ fontFamily: FONT_MONO, fontSize: 11, fill: C.inkSoft, fontWeight: 600 }} />
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
        <div style={{ fontSize: 11.5, color: C.muted, marginTop: 6 }}>Cada barra es Σ blastos ÷ Σ óvulos del grupo — nunca el promedio de tasas por ciclo. {ranking.length} en la lista, con scroll · pasa el cursor para ver el n.</div>
      </div>

      <div style={{ background: C.surface, border: `1px solid ${C.line}`, borderRadius: 12, padding: "16px 18px" }}>
        <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 10 }}>Detalle por médico y sucursal</div>
        <div style={{ overflow: "auto", maxHeight: 420 }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12.5 }}>
            <thead><tr style={{ color: C.muted, fontSize: 11.5, position: "sticky", top: 0, background: C.surface }}>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>#</th>
              <th style={{ textAlign: "left", padding: "6px 8px", fontWeight: 600 }}>Médico</th>
              <th style={{ textAlign: "left", padding: "6px 8px", fontWeight: 600 }}>Sucursal</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>Ciclos</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>% del total</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>Óvulos</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>Blastos</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>Óvulos/ciclo</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>Tasa</th>
            </tr></thead>
            <tbody style={{ fontFamily: FONT_MONO }}>
              {tabla.map((r, i) => (
                <tr key={i} style={{ borderTop: `1px solid ${C.lineSoft}` }}>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.muted }}>{i + 1}</td>
                  <td style={{ textAlign: "left", padding: "7px 8px", fontFamily: FONT_UI, color: C.ink }}>{r.medico}</td>
                  <td style={{ textAlign: "left", padding: "7px 8px", fontFamily: FONT_UI, color: C.inkSoft }}>{r.sucursal}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.inkSoft }}>{fmtInt(r.ciclos)}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.muted }}>{data.kpis.ciclos ? `${(100 * r.ciclos / data.kpis.ciclos).toFixed(1)}%` : "—"}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.inkSoft }}>{fmtInt(r.ovulos)}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.inkSoft }}>{fmtInt(r.blastos)}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.inkSoft }}>{(r.ovulos / r.ciclos).toFixed(1)}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.ink, fontWeight: 600 }}>{fmtPct(r.tasa)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={{ fontSize: 11.5, color: C.muted, marginTop: 8 }}>{tabla.length} combinaciones · con scroll · en producción: exportar CSV</div>
      </div>
    </div>
  );
}

function DashboardEmbarazoBody() {
  const [anios, setAnios] = useState(ANIOS);
  const [pais, setPais] = useState("all");
  const [rankBy, setRankBy] = useState("medico");

  const [catalogoMedicos, setCatalogoMedicos] = useState([]);
  const [catalogoSucursales, setCatalogoSucursales] = useState([]);
  const [catalogoTtos, setCatalogoTtos] = useState([]);
  const [catalogoClasificaciones, setCatalogoClasificaciones] = useState([]);
  const [catalogoRangosEdad, setCatalogoRangosEdad] = useState([]);
  const [medicos, setMedicos] = useState([]);
  const [sucursales, setSucursales] = useState([]);
  const [ttos, setTtos] = useState([]);
  const [clasificaciones, setClasificaciones] = useState([]);
  const [rangosEdad, setRangosEdad] = useState([]);
  const [catalogosListos, setCatalogosListos] = useState(false);

  const [data, setData] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch("/api/catalogos/embarazo").then((r) => r.json()).then((json) => {
      setCatalogoMedicos(json.medicos);
      setCatalogoSucursales(json.sucursales.map((s) => [s.nombre, s.pais]));
      setCatalogoTtos(json.ttos);
      setCatalogoClasificaciones(json.clasificaciones);
      setCatalogoRangosEdad(json.rangosEdad);
      setMedicos(json.medicos);
      setSucursales(json.sucursales.map((s) => s.nombre));
      setTtos(json.ttos);
      setClasificaciones(json.clasificaciones);
      setRangosEdad(json.rangosEdad);
      setCatalogosListos(true);
    }).catch((e) => setError(String(e)));
  }, []);

  useEffect(() => {
    if (!catalogosListos) return;
    const { desde, hasta } = aniosARango(anios);
    const params = new URLSearchParams({ desde, hasta, pais });
    if (anios.length < ANIOS.length) anios.forEach((a) => params.append("anio", a));
    if (medicos.length < catalogoMedicos.length) medicos.forEach((m) => params.append("medico", m));
    if (sucursales.length < catalogoSucursales.length) sucursales.forEach((s) => params.append("sucursal", s));
    if (ttos.length < catalogoTtos.length) ttos.forEach((t) => params.append("tratamiento", t));
    if (clasificaciones.length < catalogoClasificaciones.length) clasificaciones.forEach((c) => params.append("clasificacion", c));
    if (rangosEdad.length < catalogoRangosEdad.length) rangosEdad.forEach((r) => params.append("rango_edad", r));
    let cancelado = false;
    fetch(`/api/dashboards/embarazo?${params}`).then((r) => r.json()).then((json) => {
      if (!cancelado) { setData(json); setError(null); }
    }).catch((e) => { if (!cancelado) setError(String(e)); });
    return () => { cancelado = true; };
  }, [catalogosListos, anios, pais, medicos, sucursales, ttos, clasificaciones, rangosEdad, catalogoMedicos.length, catalogoSucursales.length, catalogoTtos.length, catalogoClasificaciones.length, catalogoRangosEdad.length]);

  const tog = (arr, set, v) => set(arr.includes(v) ? arr.filter((x) => x !== v) : [...arr, v]);

  if (error) return <div style={{ padding: 22, color: C.down }}>Error cargando el dashboard: {error}</div>;
  if (!data) return <div style={{ padding: 22, color: C.muted }}>Cargando…</div>;

  const serie = data.serie, ranking = data.ranking[rankBy], tabla = data.tabla;

  return (
    <div style={{ padding: "22px 24px" }}>
      <div style={{ marginBottom: 4 }}>
        <div style={{ fontFamily: FONT_DISPLAY, fontSize: 25, fontWeight: 600, letterSpacing: -.3 }}>Tasa de embarazo</div>
        <div style={{ fontSize: 13, color: C.muted, marginTop: 2 }}>Positivo ÷ (Positivo + Negativo) · {fmtInt(data.kpis.ciclos)} ciclos en vista</div>
      </div>

      <div style={{ display: "flex", flexWrap: "wrap", gap: 10, alignItems: "center", background: C.surface, border: `1px solid ${C.line}`, borderRadius: 12, padding: 12, margin: "14px 0 16px" }}>
        <MultiSelect label="Año" options={ANIOS} selected={anios} onToggle={(v) => tog(anios, setAnios, v)} onAll={() => setAnios(anios.length === ANIOS.length ? [] : [...ANIOS])} />
        <div style={{ width: 1, height: 22, background: C.line }} />
        <Segmented options={[{ value: "all", label: "Ambos países" }, { value: "MX", label: "México" }, { value: "US", label: "EEUU" }]} value={pais} onChange={setPais} />
        <div style={{ width: 1, height: 22, background: C.line }} />
        <MultiSelect label="Médico" options={catalogoMedicos} selected={medicos} onToggle={(v) => tog(medicos, setMedicos, v)} onAll={() => setMedicos(medicos.length === catalogoMedicos.length ? [] : [...catalogoMedicos])} />
        <MultiSelect label="Sucursal" options={catalogoSucursales.map((s) => s[0])} selected={sucursales} onToggle={(v) => tog(sucursales, setSucursales, v)} onAll={() => setSucursales(sucursales.length === catalogoSucursales.length ? [] : catalogoSucursales.map((s) => s[0]))} />
        <MultiSelect label="Tratamiento" options={catalogoTtos} selected={ttos} onToggle={(v) => tog(ttos, setTtos, v)} onAll={() => setTtos(ttos.length === catalogoTtos.length ? [] : [...catalogoTtos])} />
        <MultiSelect label="Clasificación" options={catalogoClasificaciones} selected={clasificaciones} onToggle={(v) => tog(clasificaciones, setClasificaciones, v)} onAll={() => setClasificaciones(clasificaciones.length === catalogoClasificaciones.length ? [] : [...catalogoClasificaciones])} />
        <MultiSelect label="Rango de edad" options={catalogoRangosEdad} selected={rangosEdad} onToggle={(v) => tog(rangosEdad, setRangosEdad, v)} onAll={() => setRangosEdad(rangosEdad.length === catalogoRangosEdad.length ? [] : [...catalogoRangosEdad])} />
      </div>

      <div style={{ display: "flex", gap: 12, flexWrap: "wrap", marginBottom: 16 }}>
        <Kpi label="Tasa de embarazo" value={fmtPct(data.kpis.tasa)} sub={`n=${fmtInt(data.kpis.ciclos)} ciclos`} />
        <Kpi label="Positivos" value={fmtInt(data.kpis.positivos)} sub="numerador" />
        <Kpi label="Negativos" value={fmtInt(data.kpis.negativos)} sub="resto de la base" />
        <Kpi label="Ciclos" value={fmtInt(data.kpis.ciclos)} sub="con resultado" />
      </div>

      <div style={{ background: C.surface, border: `1px solid ${C.line}`, borderRadius: 12, padding: "16px 18px 8px", marginBottom: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
          <div style={{ fontSize: 14, fontWeight: 600, color: C.ink }}>Evolución de la tasa</div>
        </div>
        <ResponsiveContainer width="100%" height={230}>
          <LineChart data={serie} margin={{ top: 4, right: 8, left: -12, bottom: 0 }}>
            <CartesianGrid stroke={C.lineSoft} vertical={false} />
            <XAxis dataKey="mes" tickFormatter={mesLabel} tick={{ fontSize: 11, fill: C.muted }} tickLine={false} axisLine={{ stroke: C.line }} />
            <YAxis unit="%" tick={{ fontSize: 11, fill: C.muted }} tickLine={false} axisLine={false} width={44} />
            <Tooltip contentStyle={{ fontFamily: FONT_UI, fontSize: 12, borderRadius: 8, border: `1px solid ${C.line}` }} labelFormatter={mesLabel} formatter={(v, n) => [v == null ? "—" : `${v}%`, n]} />
            <Line type="monotone" dataKey="tasa" name="Tasa" stroke={C.primary} strokeWidth={2.2} dot={{ r: 2.5, fill: C.primary }} activeDot={{ r: 4 }} connectNulls />
          </LineChart>
        </ResponsiveContainer>
      </div>

      <div style={{ background: C.surface, border: `1px solid ${C.line}`, borderRadius: 12, padding: "16px 18px", marginBottom: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
          <div style={{ fontSize: 14, fontWeight: 600, color: C.ink }}>Comparativo por {rankBy === "medico" ? "médico" : "sucursal"}</div>
          <Segmented options={[{ value: "medico", label: "Médico" }, { value: "sucursal", label: "Sucursal" }]} value={rankBy} onChange={setRankBy} />
        </div>
        <div style={{ maxHeight: 380, overflowY: "auto" }}>
          <ResponsiveContainer width="100%" height={ranking.length * 30 + 20}>
            <BarChart data={ranking} layout="vertical" margin={{ top: 0, right: 54, left: 8, bottom: 0 }}>
              <CartesianGrid stroke={C.lineSoft} horizontal={false} />
              <XAxis type="number" unit="%" tick={{ fontSize: 11, fill: C.muted }} tickLine={false} axisLine={false} />
              <YAxis type="category" dataKey="clave" width={rankBy === "medico" ? 168 : 108} tickFormatter={(v) => truncar(v, rankBy === "medico" ? 24 : 16)} tick={{ fontSize: 12, fill: C.inkSoft }} tickLine={false} axisLine={false} interval={0} />
              <Tooltip cursor={{ fill: C.lineSoft }} contentStyle={{ fontFamily: FONT_UI, fontSize: 12, borderRadius: 8, border: `1px solid ${C.line}` }} labelFormatter={(v) => v} formatter={(v, n, p) => [`${v}%  ·  n=${fmtInt(p.payload.ciclos)} ciclos · ${fmtInt(p.payload.positivos)} positivos`, "Tasa"]} />
              <Bar dataKey="tasa" radius={[0, 4, 4, 0]} barSize={18}>
                {ranking.map((r, i) => <Cell key={i} fill={i === 0 ? C.primary : C.primarySoft} />)}
                <LabelList dataKey="tasa" position="right" formatter={(v) => `${v}%`} style={{ fontFamily: FONT_MONO, fontSize: 11, fill: C.inkSoft, fontWeight: 600 }} />
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
        <div style={{ fontSize: 11.5, color: C.muted, marginTop: 6 }}>Cada barra es positivos ÷ total del grupo — nunca el promedio de tasas por ciclo. {ranking.length} en la lista, con scroll · pasa el cursor para ver el n.</div>
      </div>

      <div style={{ background: C.surface, border: `1px solid ${C.line}`, borderRadius: 12, padding: "16px 18px" }}>
        <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 10 }}>Detalle por médico y sucursal</div>
        <div style={{ overflow: "auto", maxHeight: 420 }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12.5 }}>
            <thead><tr style={{ color: C.muted, fontSize: 11.5, position: "sticky", top: 0, background: C.surface }}>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>#</th>
              <th style={{ textAlign: "left", padding: "6px 8px", fontWeight: 600 }}>Médico</th>
              <th style={{ textAlign: "left", padding: "6px 8px", fontWeight: 600 }}>Sucursal</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>Ciclos</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>% del total</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>Positivos</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>Negativos</th>
              <th style={{ textAlign: "right", padding: "6px 8px", fontWeight: 600 }}>Tasa</th>
            </tr></thead>
            <tbody style={{ fontFamily: FONT_MONO }}>
              {tabla.map((r, i) => (
                <tr key={i} style={{ borderTop: `1px solid ${C.lineSoft}` }}>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.muted }}>{i + 1}</td>
                  <td style={{ textAlign: "left", padding: "7px 8px", fontFamily: FONT_UI, color: C.ink }}>{r.medico}</td>
                  <td style={{ textAlign: "left", padding: "7px 8px", fontFamily: FONT_UI, color: C.inkSoft }}>{r.sucursal}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.inkSoft }}>{fmtInt(r.ciclos)}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.muted }}>{data.kpis.ciclos ? `${(100 * r.ciclos / data.kpis.ciclos).toFixed(1)}%` : "—"}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.inkSoft }}>{fmtInt(r.positivos)}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.inkSoft }}>{fmtInt(r.negativos)}</td>
                  <td style={{ textAlign: "right", padding: "7px 8px", color: C.ink, fontWeight: 600 }}>{fmtPct(r.tasa)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={{ fontSize: 11.5, color: C.muted, marginTop: 8 }}>{tabla.length} combinaciones · con scroll · en producción: exportar CSV</div>
      </div>
    </div>
  );
}

/* -- REGISTRO DE DASHBOARDS ------------------------------------------
 * Única fuente de verdad de la navegación. El menú (Sidebar) y el shell
 * (App) leen de aquí; ninguno de los dos conoce vistas concretas.
 *
 * Para agregar un dashboard nuevo:
 *   1. Escribir su componente de contenido (function MiVista() { ... }).
 *   2. Añadir una entrada aquí con view: MiVista.
 * El menú y el shell NO se tocan.
 *
 * `view` es opcional: si no hay componente (bloqueado/próximo), el shell
 * muestra PanelEstado automáticamente.
 * ------------------------------------------------------------------- */
const DASHBOARDS = [
  { id: "blastos", grupo: "Laboratorio", nombre: "Tasa de blastos", estado: "activo",
    desc: "Blastos sobre óvulos por médico y sucursal", view: DashboardBlastosBody },
  { id: "embarazo", grupo: "Resultados", nombre: "Tasa de embarazo", estado: "activo",
    desc: "Positivos sobre total de ciclos con resultado, por médico y sucursal", view: DashboardEmbarazoBody }
];


const NUMERADORES = { blastos_all: { label: "Blastos (cualquier calidad)", field: "blastos_all" }, blastos_top: { label: "Blastos bonitos (D5/D6)", field: "blastos_top" } };
const DENOMINADORES = { ov_cap: { label: "Óvulos capturados", field: "ov_cap" }, ov_mii: { label: "Óvulos MII (maduros)", field: "ov_mii" }, ov_insem: { label: "Óvulos inseminados", field: "ov_insem" } };
const ANIO_MIN = 2019;
const ANIOS = Array.from({ length: new Date().getFullYear() - ANIO_MIN + 1 }, (_, i) => String(new Date().getFullYear() - i));
const fmtInt = (n) => (n == null ? "0" : n.toLocaleString("es-MX"));
const fmtPct = (n) => (n == null ? "—" : `${n.toFixed(1)}%`);
const mesLabel = (m) => { const [y, mm] = m.split("-"); const names = ["ene","feb","mar","abr","may","jun","jul","ago","sep","oct","nov","dic"]; return `${names[+mm-1]} ${y.slice(2)}`; };
const truncar = (s, n = 20) => (s && s.length > n ? `${s.slice(0, n - 1)}…` : s);

const ICON = {
  blastos: "M12 3a9 9 0 100 18 9 9 0 000-18zm0 4a5 5 0 110 10 5 5 0 010-10z",
  embarazo: "M12 21s-7-4.5-7-10a4 4 0 018 0 4 4 0 018 0c0 5.5-7 10-7 10z",
  fecundacion: "M12 2v20M2 12h20",
  ciclos: "M4 20V10M10 20V4M16 20v-7M22 20H2",
};

// ---------- átomos UI ----------
function Segmented({ options, value, onChange }) {
  return (
    <div style={{ display: "inline-flex", background: C.lineSoft, borderRadius: 8, padding: 2 }}>
      {options.map((o) => {
        const active = o.value === value;
        return (
          <button key={o.value} onClick={() => onChange(o.value)} style={{ border: "none", cursor: "pointer", padding: "5px 11px", borderRadius: 6, fontFamily: FONT_UI, fontSize: 12.5, fontWeight: active ? 600 : 500, color: active ? C.surface : C.inkSoft, background: active ? C.primary : "transparent", transition: "all .12s" }}>
            {o.label}
          </button>
        );
      })}
    </div>
  );
}

function MultiSelect({ label, options, selected, onToggle, onAll }) {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState("");
  const allOn = selected.length === options.length;
  const filtradas = query ? options.filter((o) => o.toLowerCase().includes(query.toLowerCase())) : options;
  const cerrar = () => { setOpen(false); setQuery(""); };
  return (
    <div style={{ position: "relative" }}>
      <button onClick={() => setOpen((v) => !v)} style={{ display: "flex", alignItems: "center", gap: 6, cursor: "pointer", background: C.surface, border: `1px solid ${C.line}`, borderRadius: 8, padding: "6px 11px", fontFamily: FONT_UI, fontSize: 12.5, color: C.inkSoft, fontWeight: 500 }}>
        {label}<span style={{ color: C.muted, fontSize: 11.5 }}>{allOn ? "Todos" : `${selected.length} sel.`}</span><span style={{ color: C.muted, fontSize: 10 }}>{open ? "▲" : "▼"}</span>
      </button>
      {open && (<>
        <div onClick={cerrar} style={{ position: "fixed", inset: 0, zIndex: 10 }} />
        <div style={{ position: "absolute", top: "calc(100% + 4px)", left: 0, zIndex: 20, background: C.surface, border: `1px solid ${C.line}`, borderRadius: 10, padding: 6, minWidth: 210, boxShadow: "0 8px 24px rgba(20,48,43,.10)" }}>
          <input type="text" value={query} onChange={(e) => setQuery(e.target.value)} placeholder={`Buscar ${label.toLowerCase()}…`} autoFocus
            style={{ width: "100%", boxSizing: "border-box", fontFamily: FONT_UI, fontSize: 12.5, padding: "6px 8px", marginBottom: 6, borderRadius: 6, border: `1px solid ${C.line}`, color: C.ink, background: C.bg }} />
          <button onClick={onAll} style={{ width: "100%", textAlign: "left", cursor: "pointer", background: "none", border: "none", padding: "6px 8px", fontFamily: FONT_UI, fontSize: 12, fontWeight: 600, color: C.primary, borderRadius: 6 }}>{allOn ? "Quitar todos" : "Seleccionar todos"}</button>
          <div style={{ height: 1, background: C.lineSoft, margin: "4px 0" }} />
          <div style={{ maxHeight: 240, overflowY: "auto" }}>
            {filtradas.length === 0 && <div style={{ padding: "8px", fontFamily: FONT_UI, fontSize: 12, color: C.muted }}>Sin resultados</div>}
            {filtradas.map((o) => { const on = selected.includes(o);
              return (<button key={o} onClick={() => onToggle(o)} style={{ width: "100%", display: "flex", alignItems: "center", gap: 8, cursor: "pointer", background: on ? C.lineSoft : "none", border: "none", padding: "6px 8px", borderRadius: 6, fontFamily: FONT_UI, fontSize: 12.5, color: C.ink, textAlign: "left" }}>
                <span style={{ width: 14, height: 14, borderRadius: 4, flexShrink: 0, border: `1.5px solid ${on ? C.primary : C.muted}`, background: on ? C.primary : "transparent", display: "grid", placeItems: "center", color: "#fff", fontSize: 9 }}>{on ? "✓" : ""}</span>{o}
              </button>);
            })}
          </div>
        </div>
      </>)}
    </div>
  );
}

function Kpi({ label, value, sub, delta }) {
  const up = delta != null && delta >= 0;
  return (
    <div style={{ background: C.surface, border: `1px solid ${C.line}`, borderRadius: 12, padding: "15px 17px", flex: 1, minWidth: 150 }}>
      <div style={{ fontFamily: FONT_UI, fontSize: 11.5, color: C.muted, fontWeight: 500, letterSpacing: .2 }}>{label}</div>
      <div style={{ fontFamily: FONT_MONO, fontSize: 27, fontWeight: 600, color: C.ink, marginTop: 5, letterSpacing: -.5 }}>{value}</div>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 4 }}>
        {sub && <span style={{ fontFamily: FONT_MONO, fontSize: 11.5, color: C.muted }}>{sub}</span>}
        {delta != null && <span style={{ fontFamily: FONT_UI, fontSize: 11.5, fontWeight: 600, color: up ? C.up : C.down }}>{up ? "▲" : "▼"} {Math.abs(delta).toFixed(1)} pts</span>}
      </div>
    </div>
  );
}

// ---------- SIDEBAR ----------
function Sidebar({ open, setOpen, active, setActive }) {
  const grupos = [...new Set(DASHBOARDS.map((d) => d.grupo))];
  const badge = (estado) => {
    if (estado === "activo") return null;
    const map = { bloqueado: ["Bloqueado", C.clay], proximo: ["Pronto", C.sidebarMut] };
    const [txt, col] = map[estado];
    return <span style={{ fontSize: 9.5, fontWeight: 600, color: col, border: `1px solid ${col}`, borderRadius: 5, padding: "1px 5px", letterSpacing: .3 }}>{txt}</span>;
  };
  return (
    <div style={{ width: open ? 232 : 60, flexShrink: 0, background: C.sidebar, color: C.sidebarInk, display: "flex", flexDirection: "column", transition: "width .18s ease", overflow: "hidden" }}>
      <div style={{ display: "flex", flexDirection: "column", alignItems: open ? "flex-start" : "center", gap: 8, padding: open ? "18px 16px" : "16px 0", borderBottom: `1px solid rgba(255,255,255,.09)`, background: "#fff" }}>
        <div style={{ display: "flex", alignItems: "center", gap: open ? 12 : 0 }}>
          <img src={LOGO_INGENES} alt="Ingenes Institute" style={{ height: open ? 44 : 32, width: "auto", maxWidth: "100%", objectFit: "contain" }} />
          {open && <img src={LOGO_ANIOS} alt="20 años haciendo posible lo extraordinario" style={{ height: 38, width: "auto", maxWidth: "100%", objectFit: "contain" }} />}
        </div>
        {open && <div style={{ fontFamily: FONT_UI, fontSize: 10.5, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", color: C.primary }}>Dashboards Inteligencia Médica</div>}
      </div>

      <div style={{ flex: 1, overflowY: "auto", padding: "10px 0" }}>
        {grupos.map((g) => (
          <div key={g} style={{ marginBottom: 6 }}>
            {open && <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", color: C.sidebarMut, padding: "8px 18px 4px" }}>{g}</div>}
            {DASHBOARDS.filter((d) => d.grupo === g).map((d) => {
              const isActive = d.id === active;
              const clickable = d.estado !== "proximo";
              return (
                <button key={d.id} onClick={() => clickable && setActive(d.id)} title={d.nombre}
                  style={{ width: "100%", display: "flex", alignItems: "center", gap: 11, cursor: clickable ? "pointer" : "default", border: "none", background: isActive ? "rgba(140,198,63,.14)" : "transparent", padding: open ? "9px 16px" : "9px 0", justifyContent: open ? "flex-start" : "center", borderLeft: `2.5px solid ${isActive ? C.primarySoft : "transparent"}`, opacity: d.estado === "proximo" ? .45 : 1, textAlign: "left" }}>
                  <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={isActive ? "#fff" : C.sidebarInk} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" style={{ flexShrink: 0 }}><path d={ICON[d.id]} /></svg>
                  {open && (
                    <div style={{ minWidth: 0, flex: 1 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                        <span style={{ fontFamily: FONT_UI, fontSize: 13, fontWeight: isActive ? 600 : 500, color: isActive ? "#fff" : C.sidebarInk, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{d.nombre}</span>
                        {badge(d.estado)}
                      </div>
                    </div>
                  )}
                </button>
              );
            })}
          </div>
        ))}
      </div>

      <div style={{ borderTop: `1px solid rgba(255,255,255,.09)`, padding: open ? "12px 16px" : "12px 0", display: "flex", alignItems: "center", justifyContent: open ? "space-between" : "center", gap: 8 }}>
        {open && <span style={{ fontFamily: FONT_MONO, fontSize: 10.5, color: C.sidebarMut }}>sync n8n · 06:00</span>}
        <button onClick={() => setOpen((v) => !v)} style={{ background: "none", border: "none", cursor: "pointer", color: C.sidebarMut, fontSize: 15, padding: 4 }} title={open ? "Colapsar" : "Expandir"}>{open ? "«" : "»"}</button>
      </div>
    </div>
  );
}

// ---------- panel de dashboard bloqueado / próximo ----------
function PanelEstado({ d }) {
  const bloqueado = d.estado === "bloqueado";
  return (
    <div style={{ padding: "40px 28px", maxWidth: 640 }}>
      <div style={{ fontFamily: FONT_DISPLAY, fontSize: 24, fontWeight: 600 }}>{d.nombre}</div>
      <div style={{ display: "inline-block", marginTop: 12, fontSize: 12, fontWeight: 600, color: bloqueado ? C.clay : C.muted, border: `1px solid ${bloqueado ? C.clay : C.line}`, borderRadius: 6, padding: "3px 9px" }}>
        {bloqueado ? "Bloqueado — falta un paso de datos" : "Próximo — por definir"}
      </div>
      {bloqueado ? (
        <div style={{ marginTop: 20, fontSize: 14, color: C.inkSoft, lineHeight: 1.6 }}>
          <p>Este dashboard cruza <code style={{ fontFamily: FONT_MONO, background: C.lineSoft, padding: "1px 5px", borderRadius: 4 }}>gran_consolidado_fiv</code> con <code style={{ fontFamily: FONT_MONO, background: C.lineSoft, padding: "1px 5px", borderRadius: 4 }}>seguimiento_betas</code>, pero el cruce hoy trae 0% de coincidencias.</p>
          <p style={{ marginTop: 12 }}>Para desbloquearlo hay que verificar el formato del protocolo en ambas tablas y probar la cobertura sobre un año con desenlaces (2022). El diagnóstico está en el README.</p>
        </div>
      ) : (
        <div style={{ marginTop: 20, fontSize: 14, color: C.inkSoft, lineHeight: 1.6 }}>{d.desc}. Se construirá con la misma estructura del dashboard de blastos.</div>
      )}
    </div>
  );
}



// ---------- SHELL ----------
export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [active, setActive] = useState("blastos");
  const d = DASHBOARDS.find((x) => x.id === active);
  const Vista = d && d.view;   // el registro decide qué se pinta
  return (
    <div style={{ display: "flex", minHeight: 600, background: C.bg, fontFamily: FONT_UI, color: C.ink }}>
      <Sidebar open={sidebarOpen} setOpen={setSidebarOpen} active={active} setActive={setActive} />
      <div style={{ flex: 1, minWidth: 0, overflowY: "auto" }}>
        {Vista ? <Vista /> : <PanelEstado d={d} />}
      </div>
    </div>
  );
}
